#include <iostream>
#include <string>
#include <unordered_map>

class Session {
public:
    std::unordered_map<std::string, std::string> data;
    int expireTime;

    Session() : expireTime(0) {}
};

class Cache {
private:
    std::unordered_map<int, Session*> sessions;
    std::unordered_map<int, bool> expiredSessions;

public:
    void createSession(int sessionId, const std::unordered_map<std::string, std::string>& data) {
        if (sessions.find(sessionId) != sessions.end()) {
            delete sessions[sessionId];
        }
        sessions[sessionId] = new Session();
        for (const auto& pair : data) {
            sessions[sessionId]->data[pair.first] = pair.second;
        }
    }

    std::unordered_map<std::string, std::string> accessSession(int sessionId) {
        if (sessions.find(sessionId) == sessions.end()) {
            return {};
        }
        return sessions[sessionId]->data;
    }

    void invalidateSession(int sessionId) {
        expiredSessions[sessionId] = true;
    }

    bool isExpired(int sessionId) {
        auto it = sessions.find(sessionId);
        if (it != sessions.end() && expiredSessions.find(sessionId) != expiredSessions.end()) {
            delete it->second;
            sessions.erase(it);
            return true;
        }
        return false;
    }

    void expireSessions() {
        for (auto& pair : sessions) {
            if (pair.second->expireTime <= time(0)) {
                expiredSessions[pair.first] = true;
                delete pair.second;
                sessions.erase(pair.first);
            }
        }
    }
};

